    profile_id, employee_id, action,
    previous_data, new_data,
    version_before, version_after,
    actor_id, actor_role)
SELECT p.profile_id, p.employee_id, 'CREATED',
       NULL,
       jsonb_build_object('partTimeFraction', 1.000, 'position', NULL, 'enhedLabel', p.enhed_label),
       NULL, 1,
       'DEMO_SEED', 'SYSTEM'
FROM employee_profiles p
WHERE p.employee_id LIKE 'demo\_%'
  AND p.effective_to IS NULL
  AND p.enhed_label IS NOT NULL
  AND NOT EXISTS (
      SELECT 1 FROM employee_profile_audit a
      WHERE a.profile_id = p.profile_id AND a.action = 'CREATED'
  );

